import React, {createContext, useContext, useEffect, useState, ReactNode} from 'react';
import {initStripe, StripeProviderProps} from '@stripe/stripe-react-native';
import IAPManager from './IAPManager';
import WalletManager from './WalletManager';

type PaymentContextType = {
  iap: IAPManager;
  wallet: WalletManager;
  initialized: boolean;
};

const PaymentContext = createContext<PaymentContextType | null>(null);

type Props = StripeProviderProps & {children: ReactNode};

export const PaymentProvider = ({publishableKey, merchantIdentifier, children}: Props) => {
  const [initialized, setInitialized] = useState(false);
  const [iap] = useState(() => new IAPManager());
  const [wallet] = useState(() => new WalletManager());

  useEffect(() => {
    (async () => {
      await initStripe({publishableKey, merchantIdentifier});
      await iap.init();
      setInitialized(true);
    })();
    return () => {
      iap.endConnection();
    };
  }, [publishableKey, merchantIdentifier, iap]);

  return (
    <PaymentContext.Provider value={{iap, wallet, initialized}}>
      {children}
    </PaymentContext.Provider>
  );
};

export const usePayment = () => {
  const ctx = useContext(PaymentContext);
  if (!ctx) throw new Error('usePayment must be used within PaymentProvider');
  return ctx;
};

// IAPManager.ts
import * as RNIap from 'react-native-iap';

class IAPManager {
  private products: RNIap.Product[] = [];
  async init() {
    await RNIap.initConnection();
    await this.getProducts();
  }
  async endConnection() {
    try {
      await RNIap.endConnection();
    } catch {}
  }
  async getProducts(productIds: string[] = []) {
    if (!productIds.length) return this.products;
    this.products = await RNIap.getProducts(productIds);
    return this.products;
  }
  async purchaseProduct(sku: string) {
    const purchase = await RNIap.requestPurchase({sku, andDangerouslyFinishTransactionAutomaticallyIOS: false});
    return purchase;
  }
  async finishTransaction(purchase: RNIap.Purchase) {
    if (purchase.transactionReceipt) {
      await RNIap.finishTransaction({purchase, isConsumable: false});
    }
  }
}

export default IAPManager;

// WalletManager.ts
import {useStripe, PresentPaymentSheetResult} from '@stripe/stripe-react-native';

class WalletManager {
  private stripe = useStripe();
  async createPaymentIntent(clientSecret: string) {
    await this.stripe.initPaymentSheet({paymentIntentClientSecret: clientSecret});
  }
  async presentPaymentSheet(): Promise<PresentPaymentSheetResult> {
    return await this.stripe.presentPaymentSheet();
  }
}

export default WalletManager;

// PaymentButton.tsx
import React, {useCallback, useState} from 'react';
import {ActivityIndicator, Pressable, Text} from 'react-native';
import {usePayment} from './PaymentContext';

type Props = {
  sku: string;
  title: string;
};

const PaymentButton = ({sku, title}: Props) => {
  const {iap, initialized} = usePayment();
  const [loading, setLoading] = useState(false);

  const handlePress = useCallback(async () => {
    if (!initialized) return;
    setLoading(true);
    try {
      const purchase = await iap.purchaseProduct(sku);
      await iap.finishTransaction(purchase);
    } catch (e) {
      // handle errors / cancellations
    } finally {
      setLoading(false);
    }
  }, [iap, sku, initialized]);

  return (
    <Pressable onPress={handlePress} disabled={loading || !initialized}>
      {loading ? <ActivityIndicator /> : <Text>{title}</Text>}
    </Pressable>
  );
};

export default PaymentButton;

